import{_ as e,o as t,c as r,Q as o}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Reports","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reports/index.md","filePath":"guide/reports/index.md","lastUpdated":1773939149000}'),a={name:"guide/reports/index.md"},s=o('<h1 id="reports" tabindex="-1">Reports <a class="header-anchor" href="#reports" aria-label="Permalink to &quot;Reports&quot;">​</a></h1><p>Reports let you generate documents from your project data — Bills of Materials, production spreadsheets, QR stickers, quality control PDFs, and more.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-report">Creating a Report</a></li><li><a href="#report-status">Report Status</a></li><li><a href="#versioning">Versioning</a></li><li><a href="#content-selection">Content Selection</a></li><li><a href="#project-reports-vs-company-reports">Project Reports vs. Company Reports</a></li><li><a href="#report-types">Report Types</a><ul><li><a href="#bills-of-materials">Bills of Materials</a></li><li><a href="#project-reports">Project Reports</a></li><li><a href="#machine-files">Machine Files</a></li></ul></li></ul></nav><h2 id="creating-a-report" tabindex="-1">Creating a Report <a class="header-anchor" href="#creating-a-report" aria-label="Permalink to &quot;Creating a Report&quot;">​</a></h2><ol><li>Open a project and go to the <strong>Reports</strong> tab, or go to <strong>Company Reports</strong> for company-wide reports.</li><li>Click the <strong>New Report</strong> button.</li><li>In the report form dialog: <ul><li>Select the <strong>document type</strong> (e.g., Plates BoM, Production Excel).</li><li>Choose which <strong>assemblies or modules</strong> to include.</li><li>Configure any <strong>options</strong> specific to the report type.</li></ul></li><li>Click <strong>Submit</strong> to queue the report for generation.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also click <strong>Save Without Generating</strong> to create the report entry without starting generation. This is useful if you want to configure the report now and generate it later.</p></div><h2 id="report-status" tabindex="-1">Report Status <a class="header-anchor" href="#report-status" aria-label="Permalink to &quot;Report Status&quot;">​</a></h2><p>Once submitted, a report goes through these stages:</p><table><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Waiting</strong></td><td>Queued for processing</td></tr><tr><td><strong>Working</strong></td><td>Being generated (progress percentage shown)</td></tr><tr><td><strong>Ready</strong></td><td>Successfully generated — click to download</td></tr><tr><td><strong>Failed</strong></td><td>An error occurred during generation</td></tr></tbody></table><p>When a report fails, you&#39;ll receive an email notification.</p><h2 id="versioning" tabindex="-1">Versioning <a class="header-anchor" href="#versioning" aria-label="Permalink to &quot;Versioning&quot;">​</a></h2><p>Each time you regenerate a report, a new version is created. All previous versions are kept and can be downloaded from the version history.</p><div class="info custom-block"><p class="custom-block-title">Design Updates</p><p>If a design&#39;s IFC file is updated after a report was generated, a warning icon will appear next to the report. This means the report may contain outdated data. You can regenerate it to include the latest design changes.</p></div><h2 id="content-selection" tabindex="-1">Content Selection <a class="header-anchor" href="#content-selection" aria-label="Permalink to &quot;Content Selection&quot;">​</a></h2><p>Most reports require you to select which content to include:</p><ul><li><strong>Assemblies / Modules</strong> — Select specific items from the project tree.</li><li><strong>Part Batches</strong> — Some reports allow selecting by part batch instead, which groups parts across assemblies.</li></ul><h2 id="project-reports-vs-company-reports" tabindex="-1">Project Reports vs. Company Reports <a class="header-anchor" href="#project-reports-vs-company-reports" aria-label="Permalink to &quot;Project Reports vs. Company Reports&quot;">​</a></h2><p><strong>Project reports</strong> are generated from a specific project&#39;s data. Most report types are project-scoped, including all Bills of Materials and machine files.</p><p><strong>Company reports</strong> are available when you need data across all projects. These include:</p><ul><li>Production Excel</li><li>Worktime Excel</li><li>Quality Control Report</li><li>Issues Report</li></ul><p>Company reports use a <strong>date range</strong> filter instead of content selection, and can optionally be filtered by production line.</p><h2 id="report-types" tabindex="-1">Report Types <a class="header-anchor" href="#report-types" aria-label="Permalink to &quot;Report Types&quot;">​</a></h2><h3 id="bills-of-materials" tabindex="-1">Bills of Materials <a class="header-anchor" href="#bills-of-materials" aria-label="Permalink to &quot;Bills of Materials&quot;">​</a></h3><p>PDF documents listing the parts needed for your constructibles:</p><ul><li><a href="/guide/reports/plates_bom/"><strong>Plates BoM</strong></a> — All plate parts with quantities and dimensions.</li><li><a href="/guide/reports/wood_bom/"><strong>Wood BoM</strong></a> — All wood/profile parts.</li><li><a href="/guide/reports/designs_bom/"><strong>Per-Design BoM</strong></a> — One BoM per unique design.</li><li><a href="/guide/reports/accesories_bom/"><strong>Accessories BoM</strong></a> — Accessories and hardware list.</li><li><a href="/guide/reports/custom_woodcsv/"><strong>Custom Woods CSV</strong></a> — Wood parts exported as CSV.</li><li><a href="/guide/reports/custom_platecsv/"><strong>Custom Plates CSV</strong></a> — Plate parts exported as CSV.</li><li><a href="/guide/reports/custom_accesorycsv/"><strong>Custom Accessories CSV</strong></a> — Accessories exported as CSV.</li></ul><h3 id="project-reports" tabindex="-1">Project Reports <a class="header-anchor" href="#project-reports" aria-label="Permalink to &quot;Project Reports&quot;">​</a></h3><ul><li><a href="/guide/reports/production_excel/"><strong>Production Excel</strong></a> — Production planning spreadsheet.</li><li><a href="/guide/reports/worktime_excel/"><strong>Worktime Excel</strong></a> — Worker time tracking spreadsheet.</li><li><a href="/guide/reports/quality_control/"><strong>Quality Control Report</strong></a> — PDF summarizing quality control records.</li><li><a href="/guide/reports/issues/"><strong>Issues Report</strong></a> — PDF listing all issues found during production.</li><li><a href="/guide/reports/qr_stickers/"><strong>QR Stickers</strong></a> — Printable QR code labels for physical identification.</li></ul><h3 id="machine-files" tabindex="-1">Machine Files <a class="header-anchor" href="#machine-files" aria-label="Permalink to &quot;Machine Files&quot;">​</a></h3><p>Machine-specific file formats for CNC equipment. See the <a href="/guide/machine_files/formats/panel_mob1/">Machine Files</a> section for details.</p>',29),i=[s];function n(l,c,p,d,u,h){return t(),r("div",null,i)}const m=e(a,[["render",n]]);export{f as __pageData,m as default};
